#!/bin/bash
for file in "it.lproj/Localizable.strings" "en.lproj/Localizable.strings"; do
    sed -i '' 's/"story.redhood.scene8.text1" = "A woodcutter passing by heard Little Red Riding Hood'\''s loud screams coming from the cottage. He ran as fast as he could and burst through the door with a large wooden stick.\\n\\nSeeing the brave woodcutter, the cowardly wolf panicked, jumped out of the window, and ran deep into the forest, never to be seen again.\\n\\nHearing that the danger was over, the grandmother finally came out of the closet. Both she and Little Red Riding Hood were completely safe and sound.";/"story.redhood.scene8.text1" = "A woodcutter passing by heard Little Red Riding Hood'\''s loud screams coming from the cottage. He ran as fast as he could and burst through the door with a large wooden stick.\\n\\nSeeing the brave woodcutter, the cowardly wolf panicked, jumped out of the window, and ran deep into the forest, never to be seen again.";/g' "$file"

    sed -i '' 's/"story.redhood.scene8.text2" = "\\"Thank you! You saved us just in time,\\" the grandmother cheered.\\n\\nAt sunset, the mother arrived at the cottage, terrified because her daughter was late. When she saw everyone safe, she wept with joy.\\n\\nAs Little Red Riding Hood and her mother walked back home together under the trees, the little girl held her mother'\''s hand tightly and said: \\"From now on, we will always stick to the path, without any distractions!\\";/"story.redhood.scene8.text2" = "Hearing that the danger was over, the grandmother finally came out of the closet.\\n\\nLittle Red Riding Hood and her grandmother hugged each other tightly, so happy to be completely safe and sound at last!";/g' "$file"
done
